class Tumpukan:
    def __init__(self):
        self.data = []

    def push(self, item):
        self.data.append(item)

    def pop(self):
        if self.data:
            return self.data.pop()
        return None

    def peek(self):
        if self.data:
            return self.data[-1]
        return None

t = Tumpukan()
t.push(1)
t.push(2)
t.push(3)
print(t.peek())  # 3
print(t.pop())   # 3
